import { h, render } from 'preact';
import Markup  from 'preact-markup';
import { useState, useCallback, useEffect } from 'preact/hooks';
import { audioData } from './audiodata';
import { configs } from './configs';
import { fnmap } from './fnmap';


const Verse = ({ style, number, sid, children }) => (
    <span class={style} id={sid}>{ number }</span>
);


function PageElement(props){
    const elem = props.cons;
  


    const playAudio = (fname, number) => {
        props.reportAudioClick(fname, number);
    };


    const Para =({ style, children }) => {
        if (style === 'is' && children[0] === configs.book_intro_name){
            console.log('PENGANTAR found');
            var pengId = props.bookCode + '-' + configs.book_intro_name;
            props.logChapter(configs.book_intro_display_name, pengId);
            return (
                <div class={style} id={pengId}>
                    { children }
                </div>
            ); 
        }
        return (
            <div class={style}>
                { children }
            </div>
        );
    }


    

    const Chapter = ({ style, number, sid, children }) => {
        if (!number){
            return null;
        }
        //props.logChapter(number, sid);
        
        
        if (props.bookCode in audioData && number in audioData[props.bookCode]){
            return (
                <div class="chapter-number-audio-wrapper" id={sid}>
                    <span class={style} >{ number }</span>
                    <button 
                        class="mdl-button mdl-js-button" 
                        onclick={() => playAudio(audioData[props.bookCode][number], number)}>
                    dengerke
                    </button>
                </div>
            );
        } else {
            return (
                <div class="chapter-number-audio-wrapper" id={sid}>
                    <span class={style} >{ number }</span>
                </div>
            );
        }
    };


    const Note = ({ style, caller, children }) => {
        props.updateFnCounter();
        let counter = props.getNewFnCounter();
        return <span class={"footnote fnbodyhidden " + style} 
            onclick={() => props.showParatextContent('FN', children)}><sup>{ counter }</sup></span>
    };

    const Ref = ({loc, children}) => {
        const inApp = props.books.some(x => loc.includes(x.code));
        if (inApp) {
            return <span 
                    class="ref"
                    onclick={() => props.showParatextContent('XR', [loc, children])}>{ children }</span>
        } else {
            return <span 
                    class="notinapp">{ children }</span>
        }
    };

    const Char = ({ style, children }) => {
        switch (style) {
            case 'w':
                return <span class={"glospan footnote " + style} onclick={() => props.showParatextContent('GLO', children)}>{ children }</span>
                break;
            case 'fq': 
                return (
                    <div class="mdl-card__title">
                        <h2 class="mdl-card__title-text">{ children }</h2>
                    </div>
                );
                break;
            case 'fr': 
                    return null;
                    break;
            case 'xo':
                return null;
                break;
            case 'xt':
                return <span class={style} >{ children }</span>
                break;
            default:
                return <span class={style}>{ children }</span>
        }        
    };


    return <Markup markup={elem.outerHTML} type="xml" components={{ Para, Char, Chapter, Verse, Note, Ref}} />
}

function filterElems(data) {
    if (['book'].includes(data.nodeName)) {
        return false;
    } else if(data.attributes.style){
        if (['toc', 'toc1', 'toc2', 'toc3', 'h'].includes(data.attributes.style.nodeValue)) {
            return false;
        }
    }
    return true;
}

export function BookRenderer(props) {
    const [xmlData, setXmlData] = useState(null);
    const [bookCode, setBookCode] = useState('');
    const parser = new DOMParser();
    var fnCounter = 0;
    const chapterData = []
    const incrementFnCaller = () => fnCounter = fnCounter + 1;

    const getFnCounter = () => {        
        return fnmap[fnCounter];
    };

    const logChapterInfo = (n, id) => {
        if(n) {
            chapterData.push({number: n, cid: id});
            props.updateChapters(chapterData);
        }
    };

    

    useEffect(() =>
        fetch(props.filePath).then(resp => resp.text()).then( (text) =>{
            var xml = parser.parseFromString(text, 'text/xml');
            chapterData.length = 0;
            var bookData = xml.getElementsByTagName('book')[0];
            var bookCodeInfo = bookData.attributes.getNamedItem('code').value;
            setBookCode(bookCodeInfo);
            props.reportNewBookCode(bookCodeInfo);
            setXmlData(xml);
        }), [props.filePath]);

    
    const renderItems = (elems) => {
        if (!elems || elems.length < 1){
            return [];
        }

        const items = [];

        for (const [i, item] of elems.entries()) {
            items.push(<PageElement 
                cons={item}
                bookCode={bookCode} 
                books={props.books}
                logChapter={logChapterInfo}
                getNewFnCounter={getFnCounter} 
                updateFnCounter={incrementFnCaller}
                showParatextContent={props.showFnGlo}
                reportAudioClick={props.reportAudioClick}
                />);
        }
        //props.reportRenderDone();
        return items;
    };

    return (
        <main class="mdl-layout__content" id="mainelem">
            <div id="content">
                {xmlData && renderItems(Array.from(xmlData.firstChild.children).filter(filterElems))}
            </div>
        </main>
    );
}