import './style';
import { h, render, Component, toChildArray, cloneElement } from 'preact';
import { PageHeader } from './pageheader';
import { BookRenderer } from './bookRenderer';
import { useCallback, useRef, useState, useEffect } from 'preact/hooks';
import { PageFooter } from './pagefooter';
import Markup  from 'preact-markup';
import { configs } from './configs';
import { audioData } from './audiodata';
import { gloData } from './glodata';
import { chapterData } from './chapterdata';
import root from 'window-or-global';


function App(props){
	const [chapters, setChapters] = useState([]);
	const [curChapter, setCurChapter] = useState('1');
	const [audioPath, setAudioPath] = useState('');
	const [nextAudio, setNextAudio] = useState('');
	const [prevAudio, setPrevAudio] = useState('');
	const [nextAudioNum, setNextAudioNum] = useState('');
	const [prevAudioNum, setPrevAudioNum] = useState('');
	const [bookCode, setBookCode] = useState('');
	const [fnGLoCons, setFnGLoCons] = useState('');
	const [fnGLoTitle, setFnGLoTitle] = useState('');
	const [books, setBooks] = useState([{name: "Yunus", code: "JON", fpath: "./data/032JON.usx"}, 
	{name: "Yahya", code: "JHN", fpath: "./data/043JHN.usx"}]);
	const [curBook, setCurBook] = useState(books[0]);
	const cref = useRef(null);
	const toastRef = useRef(null);


	const addOne = (x) => {
        var i = parseInt(x);
        return (i + 1).toString();
    };

    const subtractOne = (x) => {
        var i = parseInt(x);
        return (i - 1).toString();
    }

	const playAudio = (fname, number) => {
		var next = '';
		var nextNum = addOne(number);;
		var prev = '';
		var prevNum = subtractOne(number);

		if (nextNum in audioData[bookCode]){
			next = audioData[bookCode][nextNum];
		} else {
			nextNum = '';
		}
		if (prevNum in audioData[bookCode]){
			prev = audioData[bookCode][prevNum];
		} else {
			prevNum = '';
		}
		console.log(fname);
		setNextAudio(next);
		setNextAudioNum(nextNum);
		setPrevAudio(prev);
		setPrevAudioNum(prevNum);
		console.log("next: " + next);
		console.log("prev: " + prev);
		setAudioPath(fname);
	};

	const updateBook = useCallback((newBook) => {
		setCurBook(newBook);
	}, [curBook]);


	function throttle(func, wait = 100) {
        let timer = null;
        return function(...args) {
            if (timer === null) {
            timer = setTimeout(() => {
                func.apply(this, args);
                timer = null;
            }, wait);
            }
        };
    }

    
    // function that fires when we scroll
    const checkOffset = () => {
		console.log('scrollinig');
		console.log(chapterData[bookCode])
		var ids = chapters.map((x) => {return x.cid });
		console.log(ids);
		return null;
		ids.forEach((elem_id) => {
			const target = document.getElementById(elem_id);
			let reachedTop;
			// get out offsets
			const wrapperOffset = wrapper.scrollTop + wrapper.offsetTop;
			const targetOffset = target.offsetTop;
			// try to do some work
			if (wrapperOffset >= targetOffset && !reachedTop) {
				reachedTop = true;
				// element reached top do more work...
				console.log(reachedTop);
			} else if (wrapperOffset <= targetOffset && reachedTop) {
				reachedTop = false;
				// user scrolled up and element longer at top...
				console.log(reachedTop);
			}
		});
    }
    
    // throttle scroll by this much (ms)
    const SCROLL_THROTTLE = 200;
    
    // get our elements
    
    const throttledScroll = throttle(checkOffset, SCROLL_THROTTLE);


	const handlNewBookCode = (newCode) => {
		console.log('book code found')
		setBookCode(newCode);
		setChapters(chapterData[newCode])
		var elem = document.getElementById('mainelem');
		setCurChapter(chapterData[newCode][0].number);
		elem.scrollTop = 0;
		//elem.addEventListener('scroll', checkOffset);
	};

	const handleAudioNav = (newPath, newNum) => {
		playAudio(newPath, newNum);
		var chapter = chapters[newNum];
		console.log(chapter.number)
		//setCurChapter(chapter.number);
		handleCptNavRequest(chapter.cid, chapter.number)
	};

	const handleCptNavRequest = (newAddress, cptNum) => {
		console.log('nav requested to ' + cptNum + ' with address of ' + newAddress);
		setCurChapter(cptNum);
		var elem = document.getElementById(newAddress);
		console.log(elem);
		elem.scrollIntoView({behavior: "smooth", block: "start", inline: "start"});
	};
	
	const updateChapters = useCallback((newCpts) =>{ 
		//setChapters(newCpts);
	}, [chapters]);
	
	const handleRenderDone = () => {
		console.log('render done');
		if (chapters.length > 0) {
			var firstChapter = chapters[0];
			console.log(chapterData[bookCode])
			var elem = document.getElementById(firstChapter.cid);
			setCurChapter(firstChapter.number);
			elem.scrollIntoView({behavior: "smooth", block: "start", inline: "start"});
		}
	}

	const Char = ({ style, children }) => {
        if (style === 'w') {
            return <span class={"glospan footnote " + style} onclick={() => props.showParatextContent('GLO', children)}>{ children }</span>
        } else if (style == 'k') {
            return '';
        }
        return <span class={style}>{ children }</span>
    };


	const removeVerses = (x) => {
		console.log(x);
		const parts = x.split(' ')
		parts.splice(parts.length -1, 1);
		return  parts.join(' ');
	};


	const handleFnGloClick = (ptype, children) => { 
		if (ptype === 'GLO') {
			const gloid = children[0];
			if (gloid in gloData){
				const gloCons = gloData[gloid];
				setFnGLoCons(<Markup markup={gloCons} type="xml" components={{ Char }} />);
				setFnGLoTitle(gloid)
			}
		} else if (ptype === 'XR') {
			const ref = children[0];
			const prettyName = children[1][0];
			if (ref.includes(bookCode)) {
				if (ref.includes('-')) {
					var [firstVerse, rest] = ref.split('-', 2)
					var elem = document.getElementById(firstVerse);
					elem.scrollIntoView({behavior: "smooth", block: "start", inline: "start"});
				} else {
					var elem = document.getElementById(ref);
					elem.scrollIntoView({behavior: "smooth", block: "start", inline: "start"});
				}
			} else {
				console.log('ref in other book');
				const inApp = books.some(x => { ref.includes(x.code) });
				if (inApp) {
					console.log("TODO: handle xref to book in app");
				} else {
					if (toastRef.current){
						toastRef.current.MaterialSnackbar.showSnackbar(
							{message: configs.notinappyet.replace('NAME', removeVerses(prettyName))}
						);
					}
				}
			}
		} else {	
			setFnGLoCons(children);
		}
	};

	const closeFnViewer = () => {
		console.log('fn close btn clicked');
		setFnGLoCons('');
		setFnGLoTitle('');
	};

	
    


	return (
		<div class="mdl-layout mdl-js-layout mdl-layout--fixed-header">
			<PageHeader 
				chapters={chapters} 
				books={books} 
				bookName={curBook.name}
				curChapter={curChapter}
				requestCptNav={handleCptNavRequest}
				updateBook={updateBook} /> 
			<BookRenderer 
				ref={cref}
				filePath={curBook.fpath}
				books={books} 
				reportAudioClick={playAudio}
				reportNewBookCode={handlNewBookCode}
				reportRenderDone={handleRenderDone}
				showFnGlo={handleFnGloClick}
				updateChapters={updateChapters} />
			
			<PageFooter 
				currentAudioPath={audioPath}
				nextAudioPath={nextAudio}
				prevAudioPath={prevAudio}
				nextAudioNum={nextAudioNum}
				prevAudioNum={prevAudioNum}
				reportAudioNav={handleAudioNav}
				cons={fnGLoCons}
				title={fnGLoTitle}
				closeFnViewer={closeFnViewer}
				showParatextContent={handleFnGloClick} />
		<div id="toast" ref={toastRef} class="mdl-js-snackbar mdl-snackbar">
			<div class="mdl-snackbar__text"></div>
			<button class="mdl-snackbar__action" type="button"></button>
		</div>
			
		</div>
	);
}


//if (typeof window !== "undefined") { 
render(<App />, root.body);

